import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { toast } from 'react-toastify';

const CartContext = createContext();
const API_BASE = 'http://localhost:5000';

export const CartProvider = ({ children }) => {
  const [cartItems, setCartItems] = useState([]);
  const [cartTotal, setCartTotal] = useState(0);
  const [isCartOpen, setIsCartOpen] = useState(false);

  const getAuthHeaders = () => ({
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${localStorage.getItem('token')}`
  });

  const isLoggedIn = () => !!localStorage.getItem('token');

  const handleAuthError = useCallback((status) => {
    if (status === 401 || status === 403) {
      localStorage.removeItem('token');
      localStorage.removeItem('loginTimestamp');
      setCartItems([]);
      setCartTotal(0);
      window.dispatchEvent(new Event('authChange'));
      toast.warning('Your session has expired. Please log in again.');
      return true;
    }
    return false;
  }, []);

  const fetchCart = useCallback(async () => {
    if (!isLoggedIn()) return;
    try {
      const res = await fetch(`${API_BASE}/api/cart`, { headers: getAuthHeaders() });
      if (handleAuthError(res.status)) return;

      const data = await res.json();
      if (data.success) {
        setCartItems(data.items);
        setCartTotal(data.total);
      }
    } catch (err) {
      console.error('Failed to fetch cart', err);
    }
  }, []);

  // Restore cart from backend whenever app loads or token changes
  useEffect(() => {
    fetchCart();
    const onAuthChange = () => {
      if (!localStorage.getItem('token')) {
        setCartItems([]);
        setCartTotal(0);
      } else {
        fetchCart();
      }
    };
    window.addEventListener('authChange', onAuthChange);
    return () => window.removeEventListener('authChange', onAuthChange);
  }, [fetchCart]);

  const addToCart = useCallback(async (product) => {
    if (!isLoggedIn()) {
      toast.error('Please log in to add items to your cart.');
      return;
    }
    try {
      const res = await fetch(`${API_BASE}/api/cart`, {
        method: 'POST',
        headers: getAuthHeaders(),
        body: JSON.stringify(product)
      });
      if (handleAuthError(res.status)) return;

      const data = await res.json();
      if (data.success) {
        setCartItems(data.items);
        setCartTotal(data.total);
        toast.success(`${product.title} added to cart!`);
        setIsCartOpen(true);
      } else {
        toast.error(data.message);
      }
    } catch (err) {
      toast.error('Failed to add item to cart.');
    }
  }, []);

  const updateCartItem = useCallback(async (itemId, quantity) => {
    try {
      const res = await fetch(`${API_BASE}/api/cart/${itemId}`, {
        method: 'PUT',
        headers: getAuthHeaders(),
        body: JSON.stringify({ quantity })
      });
      if (handleAuthError(res.status)) return;

      const data = await res.json();
      if (data.success) {
        setCartItems(data.items);
        setCartTotal(data.total);
      }
    } catch (err) {
      toast.error('Failed to update cart.');
    }
  }, []);

  const removeFromCart = useCallback(async (itemId) => {
    try {
      const res = await fetch(`${API_BASE}/api/cart/${itemId}`, {
        method: 'DELETE',
        headers: getAuthHeaders()
      });
      if (handleAuthError(res.status)) return;

      const data = await res.json();
      if (data.success) {
        setCartItems(data.items);
        setCartTotal(data.total);
        toast.info('Item removed from cart.');
      }
    } catch (err) {
      toast.error('Failed to remove item.');
    }
  }, []);

  const clearCart = useCallback(async () => {
    try {
      await fetch(`${API_BASE}/api/cart`, { method: 'DELETE', headers: getAuthHeaders() });
      setCartItems([]);
      setCartTotal(0);
    } catch (err) {
      console.error('Failed to clear cart', err);
    }
  }, []);

  return (
    <CartContext.Provider value={{
      cartItems, cartTotal, isCartOpen,
      setIsCartOpen, fetchCart,
      addToCart, updateCartItem, removeFromCart, clearCart
    }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => useContext(CartContext);
